import{_ as a,c as t,o,ag as r}from"./chunks/framework.B-QRwBGS.js";const h=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"api/config.md","filePath":"api/config.md","lastUpdated":1782748376000}'),c={name:"api/config.md"};function i(d,e,l,u,s,n){return o(),t("div",null,e[0]||(e[0]=[r('<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>This page provides an overview of all Fracture configuration macros. These settings control the default <a href="/Fracture/api/settings#physics">Physics()</a> properties applied to Fracture <a href="/Fracture/topics/pieces">Pieces</a>, how Pieces fade out and destroy themselves, and runtime logging.</p><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><h3 id="fracture-default-collision-group" tabindex="-1"><code>FRACTURE_DEFAULT_COLLISION_GROUP</code> <a class="header-anchor" href="#fracture-default-collision-group" aria-label="Permalink to &quot;`FRACTURE_DEFAULT_COLLISION_GROUP`&quot;">​</a></h3><blockquote><p>Default: <code>1</code>.</p></blockquote><p>Default collision group assigned to all <a href="/Fracture/topics/pieces">Piece</a> fixtures.</p><hr><h3 id="fracture-default-density" tabindex="-1"><code>FRACTURE_DEFAULT_DENSITY</code> <a class="header-anchor" href="#fracture-default-density" aria-label="Permalink to &quot;`FRACTURE_DEFAULT_DENSITY`&quot;">​</a></h3><blockquote><p>Default: <code>0.5</code>.</p></blockquote><p>Default density assigned to all <a href="/Fracture/topics/pieces">Piece</a> fixtures.</p><hr><h3 id="fracture-default-restitution" tabindex="-1"><code>FRACTURE_DEFAULT_RESTITUTION</code> <a class="header-anchor" href="#fracture-default-restitution" aria-label="Permalink to &quot;`FRACTURE_DEFAULT_RESTITUTION`&quot;">​</a></h3><blockquote><p>Default: <code>0</code>.</p></blockquote><p>Default restitution (bounciness) assigned to all <a href="/Fracture/topics/pieces">Piece</a> fixtures.</p><hr><h3 id="fracture-default-friction" tabindex="-1"><code>FRACTURE_DEFAULT_FRICTION</code> <a class="header-anchor" href="#fracture-default-friction" aria-label="Permalink to &quot;`FRACTURE_DEFAULT_FRICTION`&quot;">​</a></h3><blockquote><p>Default: <code>0.2</code>.</p></blockquote><p>Default friction assigned to all <a href="/Fracture/topics/pieces">Piece</a> fixtures.</p><hr><h3 id="fracture-default-linear-damping" tabindex="-1"><code>FRACTURE_DEFAULT_LINEAR_DAMPING</code> <a class="header-anchor" href="#fracture-default-linear-damping" aria-label="Permalink to &quot;`FRACTURE_DEFAULT_LINEAR_DAMPING`&quot;">​</a></h3><blockquote><p>Default: <code>0.1</code>.</p></blockquote><p>Default linear damping assigned to all <a href="/Fracture/topics/pieces">Piece</a> fixtures.</p><hr><h3 id="fracture-default-angular-damping" tabindex="-1"><code>FRACTURE_DEFAULT_ANGULAR_DAMPING</code> <a class="header-anchor" href="#fracture-default-angular-damping" aria-label="Permalink to &quot;`FRACTURE_DEFAULT_ANGULAR_DAMPING`&quot;">​</a></h3><blockquote><p>Default: <code>0.1</code>.</p></blockquote><p>Default angular damping assigned to all <a href="/Fracture/topics/pieces">Piece</a> fixtures.</p><hr><h3 id="fracture-default-impulse-strength" tabindex="-1"><code>FRACTURE_DEFAULT_IMPULSE_STRENGTH</code> <a class="header-anchor" href="#fracture-default-impulse-strength" aria-label="Permalink to &quot;`FRACTURE_DEFAULT_IMPULSE_STRENGTH`&quot;">​</a></h3><blockquote><p>Default: <code>0</code>.</p></blockquote><p>Default outward impulse strength applied to each <a href="/Fracture/topics/pieces">Piece</a> after fracturing.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Read about setting the impulse strength and origin in <a href="/Fracture/api/settings#impulse">Impulse()</a>.</p></div><hr><h3 id="fracture-auto-reset" tabindex="-1"><code>FRACTURE_AUTO_RESET</code> <a class="header-anchor" href="#fracture-auto-reset" aria-label="Permalink to &quot;`FRACTURE_AUTO_RESET`&quot;">​</a></h3><blockquote><p>Default: <code>true</code>.</p></blockquote><p>Whether to automatically reset <a href="/Fracture/api/settings#physics">Physics()</a> and <a href="/Fracture/api/settings#impulse">Impulse()</a> parameters after each fracture call (<code>true</code>) or not (<code>false</code>).</p><h2 id="fade" tabindex="-1">Fade <a class="header-anchor" href="#fade" aria-label="Permalink to &quot;Fade&quot;">​</a></h2><h3 id="fracture-fade-enabled" tabindex="-1"><code>FRACTURE_FADE_ENABLED</code> <a class="header-anchor" href="#fracture-fade-enabled" aria-label="Permalink to &quot;`FRACTURE_FADE_ENABLED`&quot;">​</a></h3><blockquote><p>Default: <code>true</code>.</p></blockquote><p>Whether to automatically fade out Pieces over time and destroy them when faded (<code>true</code>) or not (<code>false</code>).</p><hr><h3 id="fracture-fade-settled" tabindex="-1"><code>FRACTURE_FADE_SETTLED</code> <a class="header-anchor" href="#fracture-fade-settled" aria-label="Permalink to &quot;`FRACTURE_FADE_SETTLED`&quot;">​</a></h3><blockquote><p>Default: <code>true</code>.</p></blockquote><p>Whether to begin fading only once a Piece has come to rest (<code>true</code>) or immediately after its delay (<code>false</code>).</p><hr><h3 id="fracture-fade-delay-from" tabindex="-1"><code>FRACTURE_FADE_DELAY_FROM</code> <a class="header-anchor" href="#fracture-fade-delay-from" aria-label="Permalink to &quot;`FRACTURE_FADE_DELAY_FROM`&quot;">​</a></h3><blockquote><p>Default: <code>30</code>.</p></blockquote><p>Minimum random delay in steps before a Piece begins fading.</p><hr><h3 id="fracture-fade-delay-to" tabindex="-1"><code>FRACTURE_FADE_DELAY_TO</code> <a class="header-anchor" href="#fracture-fade-delay-to" aria-label="Permalink to &quot;`FRACTURE_FADE_DELAY_TO`&quot;">​</a></h3><blockquote><p>Default: <code>40</code>.</p></blockquote><p>Maximum random delay in steps before a Piece begins fading.</p><hr><h3 id="fracture-fade-speed-from" tabindex="-1"><code>FRACTURE_FADE_SPEED_FROM</code> <a class="header-anchor" href="#fracture-fade-speed-from" aria-label="Permalink to &quot;`FRACTURE_FADE_SPEED_FROM`&quot;">​</a></h3><blockquote><p>Default: <code>0.02</code>.</p></blockquote><p>Minimum random alpha decrease per step while a Piece fades.</p><hr><h3 id="fracture-fade-speed-to" tabindex="-1"><code>FRACTURE_FADE_SPEED_TO</code> <a class="header-anchor" href="#fracture-fade-speed-to" aria-label="Permalink to &quot;`FRACTURE_FADE_SPEED_TO`&quot;">​</a></h3><blockquote><p>Default: <code>0.03</code>.</p></blockquote><p>Maximum random alpha decrease per step while a Piece fades.</p><h2 id="miscellaneous" tabindex="-1">Miscellaneous <a class="header-anchor" href="#miscellaneous" aria-label="Permalink to &quot;Miscellaneous&quot;">​</a></h2><h3 id="fracture-benchmark" tabindex="-1"><code>FRACTURE_BENCHMARK</code> <a class="header-anchor" href="#fracture-benchmark" aria-label="Permalink to &quot;`FRACTURE_BENCHMARK`&quot;">​</a></h3><blockquote><p>Default: <code>(GM_build_type == &quot;run&quot;)</code>.</p></blockquote><p>Whether to log the time taken for each fracture call to the Output window (<code>true</code>) or not (<code>false</code>). By default, this is enabled when running the game from the IDE and disabled when running from an EXE.</p>',63)]))}const p=a(c,[["render",i]]);export{h as __pageData,p as default};
